import { chromium } from 'playwright';

const STORYBOOK = 'http://localhost:6006';
const SCREENSHOTS_DIR = '.storybook/screenshots';

async function delay(ms) { return new Promise(r => setTimeout(r, ms)); }

async function main() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1600, height: 900 } });
  const page = await context.newPage();

  // Test 1: Editor loads with initial JSON (Bug 2 fix)
  console.log('Test 1: Navigating to SDUI Demo Form story...');
  await page.goto(`${STORYBOOK}/?path=/story/sdui-demo-voucher--form`, { waitUntil: 'networkidle' });
  await delay(4000);
  await page.screenshot({ path: `${SCREENSHOTS_DIR}/editor-p0-initial-load.png`, fullPage: false });
  console.log('Screenshot: editor-p0-initial-load.png');

  // Check if the editor panel has content (not empty/waiting)
  const panelFrame = page.locator('[id="storybook-panel-root"]');
  const editorContent = await panelFrame.locator('.cm-content').textContent().catch(() => null);
  console.log(`Editor content length: ${editorContent?.length ?? 'NOT FOUND'}`);
  console.log(`Editor starts with: ${editorContent?.substring(0, 80) ?? 'EMPTY'}`);

  // Test 2: Dark mode (Bug 3 fix) — set dark mode and reload
  console.log('\nTest 2: Setting dark mode...');
  await page.evaluate(() => localStorage.setItem('sb-ui-theme', 'dark'));
  await page.reload({ waitUntil: 'networkidle' });
  await delay(4000);
  await page.screenshot({ path: `${SCREENSHOTS_DIR}/editor-p0-dark-mode.png`, fullPage: false });
  console.log('Screenshot: editor-p0-dark-mode.png');

  // Test 3: Light mode for comparison
  console.log('\nTest 3: Setting light mode...');
  await page.evaluate(() => localStorage.setItem('sb-ui-theme', 'light'));
  await page.reload({ waitUntil: 'networkidle' });
  await delay(4000);
  await page.screenshot({ path: `${SCREENSHOTS_DIR}/editor-p0-light-mode.png`, fullPage: false });
  console.log('Screenshot: editor-p0-light-mode.png');

  // Test 4: Story navigation preserves editor content
  console.log('\nTest 4: Navigating to Summary story...');
  await page.goto(`${STORYBOOK}/?path=/story/sdui-demo-voucher--summary`, { waitUntil: 'networkidle' });
  await delay(4000);
  await page.screenshot({ path: `${SCREENSHOTS_DIR}/editor-p0-summary.png`, fullPage: false });
  console.log('Screenshot: editor-p0-summary.png');

  await browser.close();
  console.log('\nAll tests completed!');
}

main().catch(e => { console.error(e); process.exit(1); });

