  await page.goto(`${STORYBOOK}/?path=/story/sdui-voucherdemo--form`, { waitUntil: 'networkidle' });
  await delay(5000);
  await page.screenshot({ path: `${DIR}/editor-p0-light.png` });
  console.log('  Screenshot: editor-p0-light.png');

  // Check if waiting message is still showing
  const waitingText = await page.locator('text=Waiting for story').count();
  console.log(`  Waiting msg visible: ${waitingText > 0}`);

