  console.log('\nTest 2: Dark mode...');
  await page.evaluate(() => localStorage.setItem('sb-ui-theme', 'dark'));
  await page.reload({ waitUntil: 'networkidle' });
  await delay(5000);
  await page.screenshot({ path: `${DIR}/editor-p0-dark.png` });
